#include <bits/stdc++.h>
using namespace std;

int64_t solve(string s, vector<int64_t> order, int64_t k) {
    int64_t n = s.length();
    int64_t total_substrings = n * (n + 1) / 2;
    set<int64_t> star_positions;
    int64_t total_no_star = total_substrings;
    for (int64_t t = 0; t < n; ++t) {
        int64_t x = order[t];
        auto it = star_positions.lower_bound(x);
        int64_t predecessor = -1;
        if (it != star_positions.begin()) {
            predecessor = *(--it);
        }
        auto successor_it = star_positions.upper_bound(x);
        int64_t successor = n;
        if (successor_it != star_positions.end()) {
            successor = *successor_it;
        }
        int64_t original_length = successor - predecessor - 1;
        int64_t original_contribution = original_length * (original_length + 1) / 2;
        int64_t left_length = x - predecessor - 1;
        int64_t right_length = successor - x - 1;
        int64_t new_contribution = (left_length * (left_length + 1) / 2) + (right_length * (right_length + 1) / 2);
        total_no_star -= original_contribution;
        total_no_star += new_contribution;
        int64_t valid_count = total_substrings - total_no_star;
        if (valid_count >= k) {
            return t;
        }
        star_positions.insert(x);
    }
    return -1;
}
