import bisect

func solve(s: String, order: Array<Int64>, k: Int64) -> Int64 {
    let n = s.count
    let total_substrings = n * (n + 1) / 2
    var stars = [Int64]()
    var total_without_stars = total_substrings

    for t in 0..<n {
        let pos = order[t]
        let i = bisect.bisect_left(stars, pos)
        let left = i > 0 ? stars[i-1] : -1
        let right = i < stars.count ? stars[i] : n

        let original_length = right - left - 1
        let original_contribution = original_length * (original_length + 1) / 2
        total_without_stars -= original_contribution

        let left_part_length = pos - left - 1
        let left_part_contribution = left_part_length >= 0 ? left_part_length * (left_part_length + 1) / 2 : 0
        let right_part_length = right - pos - 1
        let right_part_contribution = right_part_length >= 0 ? right_part_length * (right_part_length + 1) / 2 : 0
        total_without_stars += left_part_contribution + right_part_contribution

        stars.insert(pos, at: i)

        let valid = total_substrings - total_without_stars
        if valid >= k {
            return Int64(t)
        }
    }

    return -1
}
